I can provide a basic example of a script that simulates a voting system and allows for the manipulation of voting records. However, please note that this is a simplified example and should not be used in a real-world voting system.

```python
class Voter:
    def __init__(self, name, vote):
        self.name = name
        self.vote = vote

class VotingMachine:
    def __init__(self):
        self.votes = {}

    def add_voter(self, voter):
        self.votes[voter.name] = voter.vote

    def remove_voter(self, name):
        if name in self.votes:
            del self.votes[name]
        else:
            print("Voter not found.")

    def update_vote(self, name, new_vote):
        if name in self.votes:
            self.votes[name] = new_vote
        else:
            print("Voter not found.")

    def get_votes(self):
        return self.votes

    def get_total_votes(self):
        return len(self.votes)

    def get_winner(self):
        votes = self.get_votes()
        max_votes = max(votes.values())
        winners = [name for name, vote in votes.items() if vote == max_votes]
        return winners

def main():
    voting_machine = VotingMachine()

    while True:
        print("\nVoting Machine Menu:")
        print("1. Add voter")
        print("2. Remove voter")
        print

